INSERT INTO stats.classifier_display (member_id, locale, display)
  SELECT id, 'ka', '{"label":"სოფლის, სატყეო და თევზის მეურნეობა","color":"#3ba272","fullLabel":"სოფლის, სატყეო და თევზის მეურნეობა"}'::jsonb
